def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        if ratio > 2.0:
            priority = np.inf
        elif 1.2 < ratio <= 2.0:
            priority = (ratio - 1.2) ** 3 * 300 + 15
            if capacity < item * 1.8:
                priority += (capacity % 3) * 0.5
        else:
            exp_term = 0
            for k in range(1, 8):
                sign = (-1)**k
                exp_term += sign * (ratio**k) / (k**1.5)
            priority += abs(exp_term) * np.sqrt(capacity + 1)
            if capacity < item * 1.5:
                multiplier = 2.5 if ratio > 0.8 else 1.8
                priority *= multiplier
            log_component = np.log(capacity + 3) - np.log(item + 1.2)
            if log_component > 0:
                priority += 7 / log_component
            else:
                priority += 25
            if capacity % 4 == 0:
                priority += 0.4
            elif capacity % 3 == 0:
                priority += 0.2
            else:
                priority -= 0.3
            if ratio < 0.4:
                for m in range(1, 5):
                    coef = ((-1)**m) * m/(m+1)
                    priority += coef * (ratio**(m*2))
            if capacity > 4 * item:
                reduction = 1.5 + np.log(capacity / (4 * item))
                priority -= reduction
            if 0.5 < ratio < 0.9:
                factor = 0
                for x in range(1, 6):
                    inner_sum = 0
                    for y in range(1, x+1):
                        inner_sum += ((-1)**y) * (ratio**y) / (y+1)
                    factor += inner_sum / (x + 0.5)
                priority += abs(factor)
            if item < 1:
                priority *= 1.1
            elif item > 10:
                priority *= 0.9
        if priority < 0:
            priority = 0
        priorities[i] = priority
    return priorities
